// FBO Creation Procedure
BEGIN
 // Step 1: Generate FBO
 glGenFramebuffers(1, &fbo);
 glBindFramebuffer(GL_FRAMEBUFFER, fbo);

 // Step 2: Create Color Texture Attachment
 glGenTextures(1, &colorTex);
 glBindTexture(GL_TEXTURE_2D, colorTex);
 glTexImage2D(GL_TEXTURE_2D, 0, GL_RGBA, width, height, 0, GL_RGBA, GL_UNSIGNED_BYTE, NULL);
 glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MIN_FILTER, GL_LINEAR);
 glTexParameteri(GL_TEXTURE_2D, GL_TEXTURE_MAG_FILTER, GL_LINEAR);
 glFramebufferTexture2D(GL_FRAMEBUFFER, GL_COLOR_ATTACHMENT0, GL_TEXTURE_2D, colorTex, 0);

 // Step 3: Create Depth Renderbuffer Attachment
 glGenRenderbuffers(1, &depthRbo);
 glBindRenderbuffer(GL_RENDERBUFFER, depthRbo);
 glRenderbufferStorage(GL_RENDERBUFFER, GL_DEPTH_COMPONENT24, width, height);
 glFramebufferRenderbuffer(GL_FRAMEBUFFER, GL_DEPTH_ATTACHMENT, GL_RENDERBUFFER, depthRbo);

 // Step 4: Check Completeness
 status = glCheckFramebufferStatus(GL_FRAMEBUFFER);
 IF status != GL_FRAMEBUFFER_COMPLETE THEN
 PRINT "FBO Incomplete: " + status;
 END IF

 // Step 5: Unbind
 glBindFramebuffer(GL_FRAMEBUFFER, 0);
END

// Two-pass Post-Processing
CONSTANTS: SCREEN_QUAD_VERTEX_DATA = [...]

// PASS 1: Render Scene to FBO
PROCEDURE RenderSceneToFBO()
 glBindFramebuffer(GL_FRAMEBUFFER, fbo);
 glViewport(0, 0, width, height);

 glClearColor(0.0, 0.0, 0.0, 1.0);
 glClear(GL_COLOR_BUFFER_BIT | GL_DEPTH_BUFFER_BIT);
 glEnable(GL_DEPTH_TEST);

 // Render 3D scene
 FOR each object IN scene DO
 BindShader(object.shader);
 SetUniforms(object.uniforms);
 DrawObject(object);
 END FOR
END PROCEDURE

// PASS 2: Render FBO texture to screen with effect
PROCEDURE RenderPostProcess()
 glBindFramebuffer(GL_FRAMEBUFFER, 0); // Default framebuffer
 glViewport(0, 0, screenWidth, screenHeight);
 glClear(GL_COLOR_BUFFER_BIT);
 glDisable(GL_DEPTH_TEST);

 BindPostProcessShader();
 BindTexture(colorTex, textureUnit=0);

 // Draw full-screen quad
 glBindVertexArray(quadVAO);
 glDrawArrays(GL_TRIANGLES, 0, 6);
END PROCEDURE

// Main Loop
WHILE windowOpen DO
 ProcessInput();
 RenderSceneToFBO();
 RenderPostProcess();
 SwapBuffers(); // Present to screen
END WHILE

// Multisampled FBO Blit to Regular FBO
BEGIN
 // Source: Multisampled FBO (msFBO) with color+depth
 // Destination: Regular FBO (fbo) with color+depth

 glBindFramebuffer(GL_READ_FRAMEBUFFER, msFbo);
 glBindFramebuffer(GL_DRAW_FRAMEBUFFER, fbo);

 // Blit color
 glReadBuffer(GL_COLOR_ATTACHMENT0);
 glDrawBuffers(1, [GL_COLOR_ATTACHMENT0]);
 glBlitFramebuffer(
 0, 0, width, height, // Source bounds
 0, 0, width, height, // Destination bounds
 GL_COLOR_BUFFER_BIT, // Which buffers
 GL_NEAREST // Filtering (NEAREST for resolve)
 );

 // Blit depth
 glDrawBuffers(0, NULL); // No color output
 glBlitFramebuffer(
 0, 0, width, height,
 0, 0, width, height,
 GL_DEPTH_BUFFER_BIT,
 GL_NEAREST
 );

 // Reset
 glBindFramebuffer(GL_FRAMEBUFFER, 0);
END

// Simplified Double Buffering Concept
BEGIN
 frontBuffer = CreateBuffer(); // Visible to user
 backBuffer = CreateBuffer(); // Drawing surface

 // Render Loop
 WHILE applicationRunning DO
 // 1. Clear back buffer
 ClearBuffer(backBuffer);

 // 2. Render frame to back buffer
 BindBuffer(backBuffer);
 RenderScene();

 // 3. Wait for vertical blank (V-sync)
 WaitForVerticalBlank();

 // 4. Swap buffers
 Swap(frontBuffer, backBuffer);

 // 5. Display front buffer
 DisplayBuffer(frontBuffer);
 END WHILE
END

